import{_ as a,o as s,c as e,a2 as n}from"./chunks/framework.BWHo9ZVz.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"part-9/ch63-go-build-compilation-and-packaging.md","filePath":"part-9/ch63-go-build-compilation-and-packaging.md"}'),t={name:"part-9/ch63-go-build-compilation-and-packaging.md"};function l(o,i,p,d,h,r){return s(),e("div",null,[...i[0]||(i[0]=[n(`<h2 id="chapter-63-go-build-compilation-and-packaging" tabindex="-1">Chapter 63: Go Build, Compilation, and Packaging <a class="header-anchor" href="#chapter-63-go-build-compilation-and-packaging" aria-label="Permalink to &quot;Chapter 63: Go Build, Compilation, and Packaging&quot;">​</a></h2><p>To manage dependencies, compile code, and package our application for production, we use Go&#39;s built-in toolchain and module system. Below is a step-by-step guide to these core commands.</p><h3 id="_1-initializing-a-module-go-mod-init" tabindex="-1">1. Initializing a Module (<code>go mod init</code>) <a class="header-anchor" href="#_1-initializing-a-module-go-mod-init" aria-label="Permalink to &quot;1. Initializing a Module (\`go mod init\`)&quot;">​</a></h3><p>Every Go project should be initialized as a module. This creates a <code>go.mod</code> file in your root directory, which tracks direct and indirect package dependencies and Go runtime constraints.</p><p>To initialize a new project module:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">package-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Example:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/username/my-microservice</span></span></code></pre></div><h3 id="_2-adding-third-party-dependencies-go-get" tabindex="-1">2. Adding Third-Party Dependencies (<code>go get</code>) <a class="header-anchor" href="#_2-adding-third-party-dependencies-go-get" aria-label="Permalink to &quot;2. Adding Third-Party Dependencies (\`go get\`)&quot;">​</a></h3><p>To add external libraries (such as Gorilla Mux, Validation frameworks, or gRPC plugins) to your module, use <code>go get</code> followed by the repository path:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Downloads and installs the Gorilla Mux routing package</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/gorilla/mux</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Downloads and installs a specific version (optional)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/gorilla/mux@v1.8.0</span></span></code></pre></div><p>This command automatically updates your <code>go.mod</code> and adds the exact package hashes to the checksum database file <code>go.sum</code> to guarantee reproducible builds.</p><h3 id="_3-cleaning-up-modules-go-mod-tidy" tabindex="-1">3. Cleaning Up Modules (<code>go mod tidy</code>) <a class="header-anchor" href="#_3-cleaning-up-modules-go-mod-tidy" aria-label="Permalink to &quot;3. Cleaning Up Modules (\`go mod tidy\`)&quot;">​</a></h3><p>As you develop, you will add, remove, and update dependencies. The <code>go mod tidy</code> command ensures that your project only tracks and bundles what is actually used in your source code. It performs the following cleanups:</p><ul><li>Adds missing dependencies needed to build your module&#39;s packages.</li><li>Removes unused modules that are no longer imported anywhere.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tidy</span></span></code></pre></div><h3 id="_4-running-code-verbously-go-run" tabindex="-1">4. Running Code Verbously (<code>go run</code>) <a class="header-anchor" href="#_4-running-code-verbously-go-run" aria-label="Permalink to &quot;4. Running Code Verbously (\`go run\`)&quot;">​</a></h3><p>During development, you can compile and run your code on the fly. To see verbose output detailing the compilation steps, import resolutions, and package search paths, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Compile and run verbously</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.go</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Compile and run all files in the current package</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>The <code>-v</code> (verbose) flag prints the names of packages as they are compiled.</p><h3 id="_5-compiling-and-packaging-go-build-go-install" tabindex="-1">5. Compiling and Packaging (<code>go build</code> &amp; <code>go install</code>) <a class="header-anchor" href="#_5-compiling-and-packaging-go-build-go-install" aria-label="Permalink to &quot;5. Compiling and Packaging (\`go build\` &amp; \`go install\`)&quot;">​</a></h3><p>When you are ready to compile your application into a production-ready, standalone binary executable:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Compile to a binary named after your directory/module</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Compile to a custom binary file name</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.go</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Compile and install the binary directly to your $GOPATH/bin folder</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>The resulting binary file has zero external runtime dependencies, making it extremely lightweight and perfect for containerization (e.g., inside Docker Scratch containers).</p>`,22)])])}const k=a(t,[["render",l]]);export{g as __pageData,k as default};
